"use client";

import React, { useState, useRef, useCallback } from "react";
import {
  DocumentUpload,
  CloseCircle,
  DocumentText,
  Image as ImageIcon,
} from "iconsax-react";
import { toast } from "sonner";

// ============================================================================
// Core Types
// ============================================================================

export interface UploadedFile {
  id: string;
  file: File;
  name: string;
  size: number;
  type: string;
  uploadResult?: Record<string, unknown>; // Provider-specific upload result
  preview?: string;
}

export interface UploadResponse {
  success: boolean;
  data?: Record<string, unknown>; // Provider-specific data (URL, key, public_id, etc.)
  error?: string;
}

export interface UploadProvider {
  name: string;
  uploadFile: (
    file: File,
    options?: Record<string, unknown>
  ) => Promise<UploadResponse>;
  uploadFiles?: (
    files: File[],
    options?: Record<string, unknown>
  ) => Promise<UploadResponse[]>;
}

export interface FileUploadProps {
  onFilesChange?: (files: UploadedFile[]) => void;
  provider?: UploadProvider | null; // null = local only
  uploadOptions?: Record<string, string>; // Provider-specific options
  acceptedTypes?: string[];
  maxFileSize?: number; // in MB
  maxFiles?: number;
  required?: boolean;
  title?: string;
  description?: string;
  className?: string;
  multiple?: boolean;
  showPreviews?: boolean;
  localMode?: boolean; // Force local-only mode (no upload)
  onUploadStart?: (file: File) => void;
  onUploadSuccess?: (file: File, result?: Record<string, unknown>) => void;
  onUploadError?: (file: File, error: string) => void;
}

// ============================================================================
// Built-in Upload Providers
// ============================================================================

export class S3Provider implements UploadProvider {
  name = "s3";
  private baseUrl: string;
  private apiKey: string;

  constructor(baseUrl: string, apiKey: string) {
    this.baseUrl = baseUrl;
    this.apiKey = apiKey;
  }

  async uploadFile(
    file: File,
    options: { folder?: string } = {}
  ): Promise<UploadResponse> {
    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("folder", options.folder || "uploads");

      const response = await fetch(`${this.baseUrl}/api/s3/upload`, {
        method: "POST",
        headers: {
          "x-api-key": this.apiKey,
        },
        body: formData,
      });

      const result = await response.json();
      return {
        success: result.success,
        data: result.file,
        error: result.error,
      };
    } catch (error) {
      return {
        success: false,
        error: (error as Error).message,
      };
    }
  }

  async uploadFiles(
    files: File[],
    options: { folder?: string } = {}
  ): Promise<UploadResponse[]> {
    try {
      const formData = new FormData();
      files.forEach((file) => formData.append("files", file));
      formData.append("folder", options.folder || "uploads");

      const response = await fetch(`${this.baseUrl}/api/s3/upload-multiple`, {
        method: "POST",
        headers: {
          "x-api-key": this.apiKey,
        },
        body: formData,
      });

      const result = await response.json();
      return result.files || [];
    } catch (error) {
      return files.map(() => ({
        success: false,
        error: (error as Error).message,
      }));
    }
  }
}

export class CloudinaryProvider implements UploadProvider {
  name = "cloudinary";
  private cloudName: string;
  private apiKey: string;

  constructor(cloudName: string, apiKey: string) {
    this.cloudName = cloudName;
    this.apiKey = apiKey;
  }

  async uploadFile(
    file: File,
    options: { preset?: string; resourceType?: string } = {}
  ): Promise<UploadResponse> {
    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("upload_preset", options.preset || "default");
      formData.append("api_key", this.apiKey);

      const resourceType =
        options.resourceType ||
        (file.type.startsWith("image/") ? "image" : "raw");
      const response = await fetch(
        `https://api.cloudinary.com/v1_1/${this.cloudName}/${resourceType}/upload`,
        {
          method: "POST",
          body: formData,
        }
      );

      const data = await response.json();

      if (data.error) {
        return {
          success: false,
          error: data.error.message,
        };
      }

      return {
        success: true,
        data: {
          url: data.secure_url,
          publicId: data.public_id,
          resourceType: data.resource_type,
          format: data.format,
        },
      };
    } catch (error) {
      return {
        success: false,
        error: (error as Error).message,
      };
    }
  }
}

export class CustomAPIProvider implements UploadProvider {
  name = "custom";
  private endpoint: string;
  private headers: Record<string, string>;

  constructor(endpoint: string, headers: Record<string, string> = {}) {
    this.endpoint = endpoint;
    this.headers = headers;
  }

  async uploadFile(
    file: File,
    options: Record<string, unknown> = {}
  ): Promise<UploadResponse> {
    try {
      const formData = new FormData();
      formData.append("file", file);

      // Add any additional options to form data
      Object.entries(options).forEach(([key, value]) => {
        formData.append(key, String(value));
      });

      const response = await fetch(this.endpoint, {
        method: "POST",
        headers: this.headers,
        body: formData,
      });

      const data = await response.json();

      return {
        success: response.ok,
        data,
        error: response.ok ? undefined : data.message || "Upload failed",
      };
    } catch (error) {
      return {
        success: false,
        error: (error as Error).message,
      };
    }
  }
}

// ============================================================================
// Helper Functions
// ============================================================================

const formatFileSize = (bytes: number): string => {
  if (bytes === 0) return "0 Bytes";
  const k = 1024;
  const sizes = ["Bytes", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + " " + sizes[i];
};

const getFileIcon = (fileType: string) => {
  if (fileType.startsWith("image/")) {
    return (
      <ImageIcon
        className="h-6 w-6 text-blue-500"
        variant="Bulk"
        color="currentColor"
      />
    );
  }
  return (
    <DocumentText
      className="h-6 w-6 text-blue-500"
      variant="Bulk"
      color="currentColor"
    />
  );
};

const createFilePreview = (file: File): Promise<string | undefined> => {
  return new Promise((resolve) => {
    if (file.type.startsWith("image/")) {
      const reader = new FileReader();
      reader.onload = (e) => resolve(e.target?.result as string);
      reader.onerror = () => resolve(undefined);
      reader.readAsDataURL(file);
    } else {
      resolve(undefined);
    }
  });
};

