type GithubStarsContextType = {
  stars: number;
  setStars: (stars: number) => void;
  currentStars: number;
  setCurrentStars: (stars: number) => void;
  isCompleted: boolean;
  isLoading: boolean;
};

const [GithubStarsProvider, useGithubStars] =
  getStrictContext<GithubStarsContextType>('GithubStarsContext');

type GithubStarsProps = WithAsChild<
  {
    children: React.ReactNode;
    username?: string;
    repo?: string;
    value?: number;
    delay?: number;
  } & UseIsInViewOptions &
  HTMLMotionProps<'div'>
>;

function GithubStars({
  ref,
  children,
  username,
  repo,
  value,
  delay = 0,
  inView = false,
  inViewMargin = '0px',
  inViewOnce = true,
  asChild = false,
  ...props
}: GithubStarsProps) {
  const { ref: localRef, isInView } = useIsInView(
    ref as React.Ref<HTMLDivElement>,
    { inView, inViewOnce, inViewMargin },
  );

  const [stars, setStars] = React.useState(value ?? 0);
  const [currentStars, setCurrentStars] = React.useState(0);
  const [isLoading, setIsLoading] = React.useState(true);
  const isCompleted = React.useMemo(
    () => currentStars === stars,
    [currentStars, stars],
  );

  const Component = asChild ? Slot : motion.div;

  React.useEffect(() => {
    if (value !== undefined && username && repo) return;
    if (!isInView) {
      setStars(0);
      setIsLoading(true);
      return;
    }

    const timeout = setTimeout(() => {
      fetch(`https://api.github.com/repos/${username}/${repo}`)
        .then((response) => response.json())
        .then((data) => {
          if (data && typeof data.stargazers_count === 'number') {
            setStars(data.stargazers_count);
          }
        })
        .catch(console.error)
        .finally(() => setIsLoading(false));
    }, delay);

    return () => clearTimeout(timeout);
  }, [username, repo, value, isInView, delay]);

  return (
    <GithubStarsProvider
      value={{
        stars,
        currentStars,
        isCompleted,
        isLoading,
        setStars,
        setCurrentStars,
      }}
    >
      {!isLoading && (
        <Component ref={localRef} {...props}>
          {children}
        </Component>
      )}
    </GithubStarsProvider>
  );
}

