"use client";

import React, { useEffect, useRef, useState, useLayoutEffect } from "react";
import { cn } from "@/lib/utils";

type ScrollAxis = "horizontal" | "vertical" | "both";

interface ScrollFadeProps {
  children: React.ReactNode;
  className?: string;
  hideScrollbar?: boolean;
  axis?: ScrollAxis;
}

export function ScrollFade({
  children,
  className,
  hideScrollbar = true,
  axis = "horizontal"
}: ScrollFadeProps) {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const contentRef = useRef<HTMLDivElement | null>(null);

  const [showLeft, setShowLeft] = useState(false);
  const [showRight, setShowRight] = useState(false);
  const [showTop, setShowTop] = useState(false);
  const [showBottom, setShowBottom] = useState(false);

  const checkScroll = () => {
    const el = containerRef.current;
    if (!el) return;

    const {
      scrollLeft,
      scrollTop,
      scrollWidth,
      scrollHeight,
      clientWidth,
      clientHeight
    } = el;

    if (axis === "horizontal" || axis === "both") {
      setShowLeft(scrollLeft > 0);
      setShowRight(
        Math.ceil(scrollLeft + clientWidth) < Math.floor(scrollWidth - 1)
      );
    }

    if (axis === "vertical" || axis === "both") {
      setShowTop(scrollTop > 0);
      setShowBottom(
        Math.ceil(scrollTop + clientHeight) < Math.floor(scrollHeight - 1)
      );
    }
  };

  useLayoutEffect(() => {
    requestAnimationFrame(checkScroll);
  }, [axis]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const onScroll = () => checkScroll();
    container.addEventListener("scroll", onScroll, { passive: true });

    const ro = new ResizeObserver(() => checkScroll());
    if (contentRef.current) ro.observe(contentRef.current);
    ro.observe(container);

    const onResize = () => checkScroll();
    window.addEventListener("resize", onResize);

    const raf = requestAnimationFrame(checkScroll);

    return () => {
      container.removeEventListener("scroll", onScroll);
      window.removeEventListener("resize", onResize);
      ro.disconnect();
      cancelAnimationFrame(raf);
    };
  }, [axis]);

  return (
    <div className="relative">
      <div
        ref={containerRef}
        className={cn(
          hideScrollbar &&
          "[scrollbar-width:none] [-ms-overflow-style:none] [&::-webkit-scrollbar]:hidden",
          axis === "horizontal" && "w-full overflow-x-auto overflow-y-hidden",
          axis === "vertical" && "h-full overflow-y-auto overflow-x-hidden",
          axis === "both" && "overflow-auto",
          className
        )}
      >
        <div
          ref={contentRef}
          className={cn(
            axis === "horizontal" && "w-fit min-w-full",
            axis === "vertical" && "h-fit min-h-full",
            axis === "both" && "min-w-full min-h-full w-fit h-fit"
          )}
        >
          {children}
        </div>
      </div>

      {(axis === "horizontal" || axis === "both") && showLeft && (
        <div
          aria-hidden
          className="pointer-events-none absolute left-0 top-0 h-full w-10 z-10"
          style={{
            background:
              "linear-gradient(to right, var(--background) 0%, transparent 100%)"
          }}
        />
      )}

      {(axis === "horizontal" || axis === "both") && showRight && (
        <div
          aria-hidden
          className="pointer-events-none absolute right-0 top-0 h-full w-10 z-10"
          style={{
            background:
              "linear-gradient(to left, var(--background) 0%, transparent 100%)"
          }}
        />
      )}

      {(axis === "vertical" || axis === "both") && showTop && (
        <div
          aria-hidden
          className="pointer-events-none absolute top-0 left-0 w-full h-10 z-10"
          style={{
            background:
              "linear-gradient(to bottom, var(--background) 0%, transparent 100%)"
          }}
        />
      )}

      {(axis === "vertical" || axis === "both") && showBottom && (
        <div
          aria-hidden
          className="pointer-events-none absolute bottom-0 left-0 w-full h-10 z-10"
          style={{
            background:
              "linear-gradient(to top, var(--background) 0%, transparent 100%)"
          }}
        />
      )}
    </div>
  );
}

"use client";

import { useRef, useState, useEffect, type FC } from "react";
import {
  motion,
  useMotionValue,
  useSpring,
  animate,
  type Transition,
} from "framer-motion";

interface ScrubSliderProps {
  initialValue?: number;
  tickCount?: number;
}

interface AnimatedNumberProps {
  value: number;
}

const SPRING: Transition = {
  stiffness: 200,
  damping: 25,
};

const AnimatedNumber: FC<AnimatedNumberProps> = ({ value }) => {
  const [display, setDisplay] = useState(value);

  useEffect(() => {
    const controls = animate(display, value, {
      duration: 0.2,
      onUpdate(latest) {
        setDisplay(Math.round(latest));
      },
    });

    return controls.stop;
  }, [value]);

  return <>{display}</>;
};

export const ScrubSlider: FC<ScrubSliderProps> = ({
  initialValue = 0,
  tickCount = 32,
}) => {
  const sliderRef = useRef<HTMLDivElement>(null);

  const x = useMotionValue(0);
  const smoothX = useSpring(x, SPRING);

  const [value, setValue] = useState(initialValue);
  const [isDragging, setIsDragging] = useState(false);
  const [step, setStep] = useState(0);
  const [sliderLeft, setSliderLeft] = useState(0);
  const [sliderWidth, setSliderWidth] = useState(0);

  const padding = 16;

  useEffect(() => {
    if (!sliderRef.current) return;

    const measure = () => {
      const rect = sliderRef.current!.getBoundingClientRect();

      const width = rect.width - padding * 2;
      const newStep = width / (tickCount - 1);

      setSliderLeft(rect.left);
      setSliderWidth(width);
      setStep(newStep);

      x.set(initialValue * newStep + padding);
    };

    measure();

    const resizeObserver = new ResizeObserver(measure);
    resizeObserver.observe(sliderRef.current);

    return () => resizeObserver.disconnect();
  }, [tickCount, initialValue, x]);

  const updateValue = (clientX: number) => {
    if (!step) return;

    let posX = clientX - sliderLeft - padding;

    posX = Math.max(0, Math.min(posX, sliderWidth));

    const snappedIndex = Math.round(posX / step);
    const snappedX = snappedIndex * step;

    setValue(snappedIndex);
    x.set(snappedX + padding);
  };

  useEffect(() => {
    const move = (e: MouseEvent) => {
      if (!isDragging) return;
      updateValue(e.clientX);
    };

    const up = () => setIsDragging(false);

    window.addEventListener("mousemove", move);
    window.addEventListener("mouseup", up);

    return () => {
      window.removeEventListener("mousemove", move);
      window.removeEventListener("mouseup", up);
    };
  }, [isDragging, step, sliderLeft, sliderWidth]);

  useEffect(() => {
    const move = (e: TouchEvent) => {
      if (!isDragging) return;
      updateValue(e.touches[0].clientX);
    };

    const end = () => setIsDragging(false);

    window.addEventListener("touchmove", move);
    window.addEventListener("touchend", end);

    return () => {
      window.removeEventListener("touchmove", move);
      window.removeEventListener("touchend", end);
    };
  }, [isDragging, step, sliderLeft, sliderWidth]);

  return (
    <div className="flex w-full flex-col items-center justify-center dark:bg-zinc-950">
      <div className="relative w-full max-w-md select-none">
        <motion.div
          style={{ left: smoothX }}
          className="pointer-events-none absolute -top-12 z-30 -translate-x-1/2"
        >
          <motion.div
            animate={{
              y: isDragging ? -4 : 0,
              scale: isDragging ? 1.05 : 1,
            }}
            transition={SPRING}
            className="rounded-xl bg-gray-900 px-3 py-1.5 text-2xl font-semibold text-white shadow-sm dark:bg-zinc-100 dark:text-zinc-900"
          >
            <AnimatedNumber value={value} />
            °C
          </motion.div>
        </motion.div>

        <div
          ref={sliderRef}
          onMouseDown={(e) => {
            setIsDragging(true);
            updateValue(e.clientX);
          }}
          onTouchStart={(e) => {
            setIsDragging(true);
            updateValue(e.touches[0].clientX);
          }}
          className="relative h-24 cursor-pointer touch-none overflow-hidden rounded-3xl border border-gray-200 bg-white shadow-md dark:border-zinc-800 dark:bg-zinc-900"
        >
          <div className="absolute inset-4">
            {Array.from({ length: tickCount }).map((_, i) => (
              <div
                key={i}
                className="absolute top-0 bottom-0 w-1 -translate-x-1/2 rounded-full bg-gray-300 dark:bg-zinc-700"
                style={{
                  left: i * step,
                }}
              />
            ))}
          </div>

          <motion.div
            style={{ left: smoothX }}
            animate={{
              scaleY: isDragging ? 1.15 : 1,
            }}
            transition={SPRING}
            className="absolute top-4 bottom-4 w-1 -translate-x-1/2 rounded-full bg-black dark:bg-white"
          />
        </div>
      </div>
    </div>
  );
};

'use client';

import * as React from 'react';
import { Dialog as SheetPrime } from 'radix-ui';
import { AnimatePresence, motion, type HTMLMotionProps } from 'motion/react';

import { cn } from '@/lib/utils';
import { XIcon } from 'lucide-react';

type SheetProps = SheetPrimitiveProps;

function Sheet(props: SheetProps) {
  return <SheetPrimitive {...props} />;
}

type SheetTriggerProps = SheetTriggerPrimitiveProps;

function SheetTrigger(props: SheetTriggerProps) {
  return <SheetTriggerPrimitive {...props} />;
}

type SheetOverlayProps = SheetOverlayPrimitiveProps;

function SheetOverlay({ className, ...props }: SheetOverlayProps) {
  return (
    <SheetOverlayPrimitive
      className={cn('fixed inset-0 z-50 bg-black/50', className)}
      {...props}
    />
  );
}

type SheetCloseProps = SheetClosePrimitiveProps;

function SheetClose(props: SheetCloseProps) {
  return <SheetClosePrimitive {...props} />;
}

type SheetContentProps = SheetContentPrimitiveProps & {
  showCloseButton?: boolean;
};

function SheetContent({
  className,
  children,
  side = 'right',
  showCloseButton = true,
  ...props
}: SheetContentProps) {
  return (
    <SheetPortalPrimitive>
      <SheetOverlay />
      <SheetContentPrimitive
        className={cn(
          'bg-background fixed z-50 flex flex-col gap-4 shadow-lg',
          side === 'right' && 'h-full w-[350px] border-l',
          side === 'left' && 'h-full w-[350px] border-r',
          side === 'top' && 'w-full h-[350px] border-b',
          side === 'bottom' && 'w-full h-[350px] border-t',
          className,
        )}
        side={side}
        {...props}
      >
        {children}
        {showCloseButton && (
          <SheetClose className="ring-offset-background focus:ring-ring data-[state=open]:bg-secondary absolute top-4 right-4 rounded-xs opacity-70 transition-opacity hover:opacity-100 focus:ring-2 focus:ring-offset-2 focus:outline-hidden disabled:pointer-events-none">
            <XIcon className="size-4" />
            <span className="sr-only">Close</span>
          </SheetClose>
        )}
      </SheetContentPrimitive>
    </SheetPortalPrimitive>
  );
}

type SheetHeaderProps = SheetHeaderPrimitiveProps;

function SheetHeader({ className, ...props }: SheetHeaderProps) {
  return (
    <SheetHeaderPrimitive
      className={cn('flex flex-col gap-1.5 p-4', className)}
      {...props}
    />
  );
}

type SheetFooterProps = SheetFooterPrimitiveProps;

function SheetFooter({ className, ...props }: SheetFooterProps) {
  return (
    <SheetFooterPrimitive
      className={cn('mt-auto flex flex-col gap-2 p-4', className)}
      {...props}
    />
  );
}

type SheetTitleProps = SheetTitlePrimitiveProps;

function SheetTitle({ className, ...props }: SheetTitleProps) {
  return (
    <SheetTitlePrimitive
      className={cn('text-foreground font-semibold', className)}
      {...props}
    />
  );
}

type SheetDescriptionProps = SheetDescriptionPrimitiveProps;

function SheetDescription({ className, ...props }: SheetDescriptionProps) {
  return (
    <SheetDescriptionPrimitive
      className={cn('text-muted-foreground text-sm', className)}
      {...props}
    />
  );
}

export {
  Sheet,
  SheetTrigger,
  SheetClose,
  SheetContent,
  SheetHeader,
  SheetFooter,
  SheetTitle,
  SheetDescription,
  type SheetProps,
  type SheetTriggerProps,
  type SheetCloseProps,
  type SheetContentProps,
  type SheetHeaderProps,
  type SheetFooterProps,
  type SheetTitleProps,
  type SheetDescriptionProps,
};



type SheetContextType = {
  isOpen: boolean;
  setIsOpen: (isOpen: boolean) => void;
};

const [SheetProvider, useSheet] =
  getStrictContext<SheetContextType>('SheetContext');

type SheetPrimitiveProps = React.ComponentProps<typeof SheetPrime.Root>;

function SheetPrimitive(props: SheetPrimitiveProps) {
  const [isOpen, setIsOpen] = useControlledState({
    value: props.open,
    defaultValue: props.defaultOpen,
    onChange: props.onOpenChange,
  });

  return (
    <SheetProvider value={{ isOpen, setIsOpen }}>
      <SheetPrime.Root
        data-slot="sheet"
        {...props}
        onOpenChange={setIsOpen}
      />
    </SheetProvider>
  );
}

type SheetTriggerPrimitiveProps = React.ComponentProps<typeof SheetPrime.Trigger>;

function SheetTriggerPrimitive(props: SheetTriggerPrimitiveProps) {
  return <SheetPrime.Trigger data-slot="sheet-trigger" {...props} />;
}

type SheetClosePrimitiveProps = React.ComponentProps<typeof SheetPrime.Close>;

function SheetClosePrimitive(props: SheetClosePrimitiveProps) {
  return <SheetPrime.Close data-slot="sheet-close" {...props} />;
}

type SheetPortalPrimitiveProps = React.ComponentProps<typeof SheetPrime.Portal>;

function SheetPortalPrimitive(props: SheetPortalPrimitiveProps) {
  const { isOpen } = useSheet();

  return (
    <AnimatePresence>
      {isOpen && (
        <SheetPrime.Portal forceMount data-slot="sheet-portal" {...props} />
      )}
    </AnimatePresence>
  );
}

type SheetOverlayPrimitiveProps = Omit<
  React.ComponentProps<typeof SheetPrime.Overlay>,
  'asChild' | 'forceMount'
> &
  HTMLMotionProps<'div'>;

function SheetOverlayPrimitive({
  transition = { duration: 0.2, ease: 'easeInOut' },
  ...props
}: SheetOverlayPrimitiveProps) {
  return (
    <SheetPrime.Overlay asChild forceMount>
      <motion.div
        key="sheet-overlay"
        data-slot="sheet-overlay"
        initial={{ opacity: 0, filter: 'blur(4px)' }}
        animate={{ opacity: 1, filter: 'blur(0px)' }}
        exit={{ opacity: 0, filter: 'blur(4px)' }}
        transition={transition}
        {...props}
      />
    </SheetPrime.Overlay>
  );
}

type Side = 'top' | 'bottom' | 'left' | 'right';

type SheetContentPrimitiveProps = React.ComponentProps<typeof SheetPrime.Content> &
  HTMLMotionProps<'div'> & {
    side?: Side;
  };

function SheetContentPrimitive({
  side = 'right',
  transition = { type: 'spring', stiffness: 150, damping: 22 },
  style,
  children,
  ...props
}: SheetContentPrimitiveProps) {
  const axis = side === 'left' || side === 'right' ? 'x' : 'y';

  const offscreen: Record<Side, { x?: string; y?: string; opacity: number }> = {
    right: { x: '100%', opacity: 0 },
    left: { x: '-100%', opacity: 0 },
    top: { y: '-100%', opacity: 0 },
    bottom: { y: '100%', opacity: 0 },
  };

  const positionStyle: Record<Side, React.CSSProperties> = {
    right: { insetBlock: 0, right: 0 },
    left: { insetBlock: 0, left: 0 },
    top: { insetInline: 0, top: 0 },
    bottom: { insetInline: 0, bottom: 0 },
  };

  return (
    <SheetPrime.Content asChild forceMount {...props}>
      <motion.div
        key="sheet-content"
        data-slot="sheet-content"
        data-side={side}
        initial={offscreen[side]}
        animate={{ [axis]: 0, opacity: 1 }}
        exit={offscreen[side]}
        style={{
          position: 'fixed',
          ...positionStyle[side],
          ...style,
        }}
        transition={transition}
      >
        {children}
      </motion.div>
    </SheetPrime.Content>
  );
}

type SheetHeaderPrimitiveProps = React.ComponentProps<'div'>;

function SheetHeaderPrimitive(props: SheetHeaderPrimitiveProps) {
  return <div data-slot="sheet-header" {...props} />;
}

type SheetFooterPrimitiveProps = React.ComponentProps<'div'>;

function SheetFooterPrimitive(props: SheetFooterPrimitiveProps) {
  return <div data-slot="sheet-footer" {...props} />;
}

type SheetTitlePrimitiveProps = React.ComponentProps<typeof SheetPrime.Title>;

function SheetTitlePrimitive(props: SheetTitlePrimitiveProps) {
  return <SheetPrime.Title data-slot="sheet-title" {...props} />;
}

type SheetDescriptionPrimitiveProps = React.ComponentProps<
  typeof SheetPrime.Description
>;

function SheetDescriptionPrimitive(props: SheetDescriptionPrimitiveProps) {
  return (
    <SheetPrime.Description data-slot="sheet-description" {...props} />
  );
}


function getStrictContext<T>(
  name?: string,
): readonly [
  ({
    value,
    children,
  }: {
    value: T;
    children?: React.ReactNode;
  }) => React.JSX.Element,
  () => T,
] {
  const Context = React.createContext<T | undefined>(undefined);

  const Provider = ({
    value,
    children,
  }: {
    value: T;
    children?: React.ReactNode;
  }) => <Context.Provider value={value}>{children}</Context.Provider>;

  const useSafeContext = () => {
    const ctx = React.useContext(Context);
    if (ctx === undefined) {
      throw new Error(`useContext must be used within ${name ?? 'a Provider'}`);
    }
    return ctx;
  };

  return [Provider, useSafeContext] as const;
}

export { getStrictContext };

interface CommonControlledStateProps<T> {
  value?: T;
  defaultValue?: T;
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useControlledState<T, Rest extends any[] = []>(
  props: CommonControlledStateProps<T> & {
    onChange?: (value: T, ...args: Rest) => void;
  },
): readonly [T, (next: T, ...args: Rest) => void] {
  const { value, defaultValue, onChange } = props;

  const [state, setInternalState] = React.useState<T>(
    value !== undefined ? value : (defaultValue as T),
  );

  React.useEffect(() => {
    if (value !== undefined) setInternalState(value);
  }, [value]);

  const setState = React.useCallback(
    (next: T, ...args: Rest) => {
      setInternalState(next);
      onChange?.(next, ...args);
    },
    [onChange],
  );

  return [state, setState] as const;
}

