function AuthorInfo({
  name,
  handle,
  verified,
  createdAt,
}: {
  name: string;
  handle: string;
  verified?: boolean;
  createdAt?: string;
}) {
  return (
    <div className="flex min-w-0 items-center gap-1">
      <span className="truncate font-semibold">{name}</span>
      {verified && (
        <VerifiedBadge className="size-[18px] shrink-0 text-blue-500" />
